private void analyzeData(InputStream in, int level) throws IOException {
        int b = in.read();
        if (b > 0 && level > 10) {
            in.close();
        } else {
            // Non-ownership API usage only; still should be considered leak.
            System.out.println("first byte = " + b);
            System.out.println("stream handle = " + in);
        }
    }
